recoveryHook := agent.NewAutoRecoveryPostLadderExhaustionHook(store, qualityRunner, rcfg, projectRoot, agent.AutoRecoveryConfig{
	MaxRecoveryCostUSD: spec.MaxRecoveryCostUSD,
	MaxBeadCostUSD:     spec.MaxBeadCostUSD,
})

harnessBilledLookup := func(harnessName string) bool {
	svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
	if svcErr != nil {
		return true
	}
	infos, err := svc.ListHarnesses(context.Background())
	if err != nil {
		return true
	}
	for _, h := range infos {
		if h.Name == harnessName {
			return escalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
		}
	}
	return true
}

costCap := escalation.NewCostCapTracker(spec.MaxCostUSD, harnessBilledLookup)
profileSelector := newImplementationProfileSelector(projectRoot)
accumulateBilledCost := func(report agent.ExecuteBeadReport) {
	costCap.Add(report.Harness, report.CostUSD)
}
costCapTripped := func() (work.StopDecision, agent.ExecuteBeadReport, bool) {
	if _, tripped := costCap.Tripped(); !tripped {
		return work.StopDecision{}, agent.ExecuteBeadReport{}, false
	}
	spent := costCap.Spent()
	decision, _ := work.ClassifyStop(work.StopInput{Budget: true})
	return decision, agent.ExecuteBeadReport{
		Status: agent.ExecuteBeadStatusExecutionFailed,
		Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, spec.MaxCostUSD),
	}, true
}

singlePolicyAttempt := func(ctx context.Context, beadID string, requestedMinPower int, requestedProfile string, routingIntent escalation.ExecutionHint, routingNote string, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
	gitOps := &agent.RealGitOps{}
	// Safety net: after the attempt returns, commit any execution-evidence
	// bundle that ExecuteBeadWithConfig published to the project root but the
	// land flow did not pick up — e.g. a terminal provider_connectivity /
	// route-failure that never produced a commit to land. Without this the
	// project worktree is left dirty after the tracker commit already landed
	// (ddx-ca94d157). Mirrors the server worker path
	// (internal/server/workers.go).
	var safetyNetAttemptID string
	defer func() {
		if safetyNetAttemptID != "" {
			_ = agent.VerifyCleanWorktree(projectRoot, safetyNetAttemptID)
		}
	}()
	attemptProvider := spec.Provider
	if resolvedProvider != "" {
		attemptProvider = resolvedProvider
	}
	reportFromResult := func(res *agent.ExecuteBeadResult) agent.ExecuteBeadReport {
		report := agent.ReportFromExecuteBeadResult(res, string(routingIntent.InferredPowerClass))
		applyExecutionRoutingIntentReport(&report, routingIntent, requestedProfile, routingNote)
		return report
	}
	loopOverrides := config.CLIOverrides{
		Harness:           resolvedHarness,
		Model:             resolvedModel,
		Provider:          attemptProvider,
		Profile:           requestedProfile,
		Effort:            spec.Effort,
		MinPower:          requestedMinPower,
		MaxPower:          spec.MaxPower,
		OpaquePassthrough: spec.OpaquePassthrough,
		AttemptBackend:    spec.AttemptBackend,
	}
	requestTimeout := spec.RequestTimeout.Duration
	if requestTimeout > 0 {
		loopOverrides.ProviderRequestTimeout = &requestTimeout
	}
	attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
	res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, executeLoopAttemptRuntime(
		spec,
		cmd.OutOrStdout(),
		bead.NewStore(ddxroot.JoinProject(projectRoot)),
		f.AgentRunnerOverride,
		resourceChecker,
	), gitOps)
	if res != nil {
		safetyNetAttemptID = res.AttemptID
	}
	if execErr != nil && res == nil {
		return agent.ExecuteBeadReport{}, execErr
	}
	if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
		return reportFromResult(res), nil
	}
	if execErr != nil {
		agent.MarkResultExecutionError(res, execErr)
		return reportFromResult(res), nil
	}
	if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
		targetBead, _ := store.Get(context.Background(), beadID)
		landRes, _, landErr := agent.SubmitWithPreMergeChecks(
			ctx, projectRoot, targetBead, res,
			func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
			bead.NewStore(ddxroot.JoinProject(projectRoot)),
			resolveClaimAssignee(), "ddx work",
			nil,
		)
		if landErr == nil {
			agent.ApplyLandResultToExecuteBeadResult(res, landRes)
			_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
		} else {
			agent.MarkResultLandError(projectRoot, res, landErr)
			_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
			return reportFromResult(res), nil
		}
	} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
		if res.ResultRev != "" && res.ResultRev != res.BaseRev {
			res.Outcome = "preserved"
		} else {
			res.Outcome = "error"
		}
		res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	} else if res != nil && res.ResultRev == res.BaseRev {
		res.Outcome = "no-changes"
		res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
	}
	return reportFromResult(res), nil
}

var ladderOnce sync.Once
var ladder escalationFloorFinder
loadLadder := func() escalationFloorFinder {
	ladderOnce.Do(func() {
		ladder = powerladder.NewLadder(nil)
		svc, svcErr := agent.ResolveServiceFromWorkDir(projectRoot)
		if svcErr != nil {
			return
		}
		modelFilter := agentlib.ModelFilter{}
		if spec.Harness != "" {
			modelFilter.Harness = spec.Harness
		}
		modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
		defer cancel()
		models, listErr := svc.ListModels(modelCtx, modelFilter)
		if listErr != nil {
			return
		}
		ladder = powerladder.NewLadder(models)
	})
	return ladder
}

executor := f.tryExecutorOverride
if executor == nil {
	executor = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		targetBead, err := store.Get(context.Background(), beadID)
		if err != nil {
			return agent.ExecuteBeadReport{}, err
		}
		routingIntent := resolveCommandExecutionHint(ctx, targetBead, noRoutingFlags, hasProjectRoutingConfig)
		inferredPolicy := routingIntent.InferredPowerClass
		initialMinPower, unavailableReport, unavailable := investigationRetryInitialMinPower(targetBead, rcfg.MinPower(), spec.MaxPower, loadLadder())
		if unavailable {
			applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, "", "")
			return unavailableReport, nil
		}
		if spec.Provider == "" && spec.Model == "" {
			if learnedMinPower, learnedUnavailableReport, learned := recentProviderConnectivityMinPower(store, time.Now().UTC(), initialMinPower, spec.MaxPower, loadLadder()); learned {
				if learnedUnavailableReport.Status != "" {
					learnedUnavailableReport.BeadID = beadID
					applyExecutionRoutingIntentReport(&learnedUnavailableReport, routingIntent, "", "")
					return learnedUnavailableReport, nil
				}
				if learnedMinPower > initialMinPower {
					initialMinPower = learnedMinPower
				}
			}
			// Pre-dispatch route-exclusion check: if every known route at
			// the requested floor is still inside the exclusion window,
			// skip this dispatch and let the retry policy raise MinPower
			// in memory for the next attempt.
			if svcForExcl, svcExclErr := agent.ResolveServiceFromWorkDir(projectRoot); svcExclErr == nil {
				if exclusionReport, skip := agent.CheckAndApplyRouteExclusions(
					ctx, svcForExcl, store, beadID, resolveClaimAssignee(),
					targetBead.Extra, time.Now().UTC(), initialMinPower,
					svcForExcl.ResolveRoute,
					func(p int) (int, error) { return nextEscalationFloor(loadLadder(), p) },
					spec.RouteResolutionTimeout.Duration,
					loopSessionID,
					time.Time{}, // lastActivityAt: caller lacks liveness snapshot; treat as stale → always count
				); skip {
					applyExecutionRoutingIntentReport(&exclusionReport, routingIntent, "", "")
					return exclusionReport, nil
				}
			}
		}
		initialProfile := spec.Profile
		initialRoutingNote := ""
		if autoInferPowerClass {
			if selection, selectErr := profileSelector.Select(ctx, inferredPolicy, initialMinPower); selectErr == nil && selection.Name != "" {
				initialProfile = selection.Name
				initialRoutingNote = selection.Note
				if spec.MaxPower > 0 && initialMinPower > 0 && initialMinPower >= spec.MaxPower {
					unavailableReport := routeUnavailableReport(targetBead, initialMinPower, spec.MaxPower, nil)
					applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, initialProfile, initialRoutingNote)
					return unavailableReport, nil
				}
			} else {
				var degradeNote string
				initialMinPower, unavailableReport, degradeNote, unavailable = zeroConfigInitialMinPower(targetBead, inferredPolicy, initialMinPower, spec.MaxPower, loadLadder())
				if unavailable {

					if unavailable {
						applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, "", "")
						return unavailableReport, nil
					}
					if degradeNote != "" {
						initialRoutingNote = degradeNote
					}
				}
			}
			perBeadBudget := spec.MaxBeadCostUSD
			if override, ok := escalation.ParseBeadBudgetLabel(targetBead.Labels); ok {
				perBeadBudget = override
			}
			perBeadTracker := escalation.NewPerBeadCostTracker(perBeadBudget, harnessBilledLookup)
			report, err := runEscalatingPowerAttempts(
				ctx,
				initialMinPower,
				loadLadder(),
				func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
					requestProfile := initialProfile
					routingNote := initialRoutingNote
					if autoInferPowerClass {
						if selection, selectErr := profileSelector.Select(ctx, inferredPolicy, requestedMinPower); selectErr == nil {
							// Empty selection means no no-extra-requirement policy covers this
							// retry floor. Drop the stale lower policy and send MinPower-only so
							// Fizeau can route or report no eligible candidate from live config.
							requestProfile = selection.Name
							if requestProfile == "" {
								routingNote = ""
							} else if selection.Note != "" {
								routingNote = selection.Note
							}
						}
					}
					return singlePolicyAttempt(ctx, beadID, requestedMinPower, requestProfile, routingIntent, routingNote, spec.Harness, spec.Provider, spec.Model)
				},
				nil,
				perBeadTracker,
				strings.TrimSpace(spec.Harness) == "" && strings.TrimSpace(spec.Provider) == "" && strings.TrimSpace(spec.Model) == "",
			)
			if err == nil {
				accumulateBilledCost(report)
			}
			return report, err
		})
	}

	worker := &agent.ExecuteBeadWorker{
		Store:    workerStore,
		Reviewer: reviewer,
		EscalationNextFloor: func(actualPower int) (int, error) {
			return nextEscalationFloor(loadLadder(), actualPower)
		},
		Executor: executor,
	}

	cliLandingOps := agent.RealLandingGitOps{}
	progressLog := cmd.OutOrStdout()
	if jsonOutput {
		progressLog = io.Discard
	}
	result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
		Mode:                         spec.Mode,
		IdleInterval:                 spec.IdleInterval.Duration,
		IgnoreCooldown:               spec.IgnoreCooldown,
		CooldownOverrideReason:       spec.CooldownOverrideReason,
		Log:                          progressLog,
		CleanupLog:                   cleanupLog,
		EventSink:                    loopSink,
		WorkerID:                     resolveClaimAssignee(),
		ProjectRoot:                  projectRoot,
		CleanupRunner:                cleanupRunner,
		ResourceChecker:              resourceChecker,
		BinaryRefreshCheck:           f.buildWorkBinaryRefreshCheck(cmd, projectRoot, tryTargetBeadID),
		ProjectRootDirtyCheck:        agent.CanonicalRootDirtyPaths,
		SessionID:                    loopSessionID,
		PreClaimHook:                 buildCLIPreClaimHook(projectRoot, cliLandingOps),
		PreClaimIntakeHook:           intakeHook,
		PreClaimTimeout:              spec.PreClaimTimeout.Duration,
		RouteResolutionTimeout:       spec.RouteResolutionTimeout.Duration,
		ClaimSuccessRateWindow:       optionalIntFlag(cmd, "claim-rate-window", agent.DefaultClaimSuccessRateWindow),
		ClaimSuccessRateThreshold:    optionalFloat64Flag(cmd, "claim-rate-threshold", agent.DefaultClaimSuccessRateThreshold),
		PreClaimWarnRepeatThreshold:  optionalIntFlag(cmd, "preclaim-warn-threshold", agent.DefaultPreClaimWarnRepeatThreshold),
		PreDispatchLintHook:          lintHook,
		PostAttemptTriageHook:        triageHook,
		ProseEvidenceHook:            proseHook,
		PostAttemptDecompositionHook: decompositionHook,
		BudgetStop:                   costCapTripped,
		NoReview:                     spec.NoReview,
		TargetBeadID:                 tryTargetBeadID,
		ReviewCostCap:                costCap,
		FinalizeDurableAudit:         f.buildAttemptAuditFinalizer(projectRoot, store),
		PostLadderExhaustionHook:     recoveryHook,
	})
	if err != nil && result != nil && (errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)) {
		_ = writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
	}
	if err != nil {
		return err
	}
	if result != nil && result.ExitReason == "binary_refresh" {
		return nil
	}
	return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
}

func (f *CommandFactory) buildAttemptAuditFinalizer(projectRoot string, store *bead.Store) func(agent.ExecuteBeadReport) error {
	if f.durableAuditFinalizeOverride != nil {
		return f.durableAuditFinalizeOverride
	}
	return func(report agent.ExecuteBeadReport) error {
		return agent.FinalizeDurableAttemptAudit(projectRoot, store, report)
	}
}

func worktreeStillLive(meta agent.ExecutionCleanupMetadata, runStates []agent.RunState, now time.Time) bool {
	if meta.Preserved || meta.ActiveCandidateCycle || strings.TrimSpace(meta.CandidateRef) != "" {
		return true
	}
	if worktreeLivenessAlive(meta.Liveness, now) {
		return true
	}
	for _, state := range runStates {
		if !runStateMatchesWorktree(state, meta) {
			continue
		}
		if strings.TrimSpace(state.CandidateCyclePhase) != "" || strings.TrimSpace(state.CandidateRef) != "" {
			return true
		}
		if worktreeRunStateAlive(state, now) {
			return true
		}
	}
	return false
}

func worktreeLivenessAlive(liveness *agent.ExecutionCleanupLiveness, now time.Time) bool {
	if liveness == nil {
		return false
	}
	if processAlive(liveness.PID) {
		return true
	}
	if !liveness.ExpiresAt.IsZero() && now.Before(liveness.ExpiresAt) {
		return true
	}
	return !liveness.RefreshedAt.IsZero() && now.Sub(liveness.RefreshedAt) <= 2*time.Minute
}

func worktreeRunStateAlive(state agent.RunState, now time.Time) bool {
	if processAlive(state.PID) {
		return true
	}
	if !state.ExpiresAt.IsZero() && now.Before(state.ExpiresAt) {
		return true
	}
	return !state.RefreshedAt.IsZero() && now.Sub(state.RefreshedAt) <= agent.RunStateLivenessTTL
}

func runStateMatchesWorktree(state agent.RunState, meta agent.ExecutionCleanupMetadata) bool {
	if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
		return true
	}
	return meta.WorktreePath != "" &&
		state.WorktreePath != "" &&
		filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath)
}

func processAlive(pid int) bool {
	if pid <= 0 {
		return false
	}
	proc, err := os.FindProcess(pid)
	if err != nil {
		return false
	}
	return proc.Signal(syscall.Signal(0)) == nil
}

func firstNonEmpty(values ...string) string {
	for _, value := range values {
		if strings.TrimSpace(value) != "" {
			return value
		}
	}
	return ""
}

func worktreeReapMaxAgeFromEnv() time.Duration {
	raw := strings.TrimSpace(os.Getenv("DDX_WORKTREE_REAP_MAX_AGE"))
	if raw == "" {
		return defaultWorktreeReapMaxAge
	}
	d, err := time.ParseDuration(raw)
	if err != nil || d <= 0 {
		return defaultWorktreeReapMaxAge
	}
	return d
}

// projectHasRoutingConfig reports whether the project's .ddx/config.yaml pins a
// routing decision that should suppress DDx's zero-config powerClass inference.
// agent.endpoints alone is transport configuration (where providers live) and
// does NOT pin routing — leaving it on the suppression list caused no-flag work
// in projects with local endpoints to send an empty Policy and inherit
// Fizeau's default policy (which, with no DDx-supplied hint, scored Opus on
// ordinary implementation work; see ddx-e0b95b4a).
func projectHasRoutingConfig(projectRoot string) bool {
	if projectRoot == "" {
		return false
	}
	cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
	if _, err := os.Stat(cfgPath); err != nil {
		return false
	}
	cfg, err := config.LoadWithWorkingDir(projectRoot)
	if err != nil || cfg == nil || cfg.Agent == nil {
		return false
	}
	a := cfg.Agent
	return strings.TrimSpace(a.Model) != ""
}

func resolveCommandExecutionHint(ctx context.Context, b *bead.Bead, noRoutingFlags, hasProjectRoutingConfig bool) escalation.ExecutionHint {
	return escalation.ResolveExecutionHint(escalation.ExecutionHintInput{
		Bead:                         b,
		ReadinessEstimatedDifficulty: agent.ReadinessEstimatedDifficultyFromContext(ctx),
		ExplicitRouting:              !noRoutingFlags,
		ProjectRouting:               hasProjectRoutingConfig,
	})
}

func applyExecutionRoutingIntentReport(report *agent.ExecuteBeadReport, intent escalation.ExecutionHint, requestedProfile, routingNote string) {
	if report == nil {
		return
	}
	report.RoutingIntentSource = string(intent.Source)
	report.EstimatedDifficulty = string(intent.EstimatedDifficulty)
	report.InferredPowerClass = string(intent.InferredPowerClass)
	report.RequestedProfile = requestedProfile
	report.RoutingIntentNote = routingNote
}

package work

import (
	"context"
	"errors"
	"fmt"
	"io"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/trackerpaths"
)

// DefaultPreClaimTimeout bounds pre-claim readiness hooks when callers do not
// provide an explicit timeout.
const DefaultPreClaimTimeout = 5 * time.Minute

const SystemicPreClaimReasonPrefix = "systemic_preclaim:"

// TrackerContentionPreClaimReasonPrefix marks a pre-claim skip caused by
// transient multi-worker contention on DDx-managed tracker/metadata files
// (.ddx/beads.jsonl, .ddx/metrics/attempts.jsonl, …) rather than a systemic
// repo-config problem. Like systemic skips it idles without cooldowning the
// bead, but it carries a distinct reason code so operators can tell transient
// contention apart from a configuration wedge (ddx-df77e668).
const TrackerContentionPreClaimReasonPrefix = "tracker_contention_preclaim:"

// preClaimClass categorizes a pre-claim hook error so the guard can choose
// between idling without cooldown (systemic / tracker-contention) and the
// per-bead two-strikes cooldown policy (bead-specific failures).
type preClaimClass int

const (
	preClaimClassBeadSpecific preClaimClass = iota
	preClaimClassSystemic
	preClaimClassTrackerContention
)

// Guard decides whether a bead may proceed. Callers use the returned reason
// for skip telemetry and logs.
type Guard interface {
	Allow(ctx context.Context, beadID string) (bool, string)
}

// cooldownStore is the minimal store surface PreClaimGuard needs.
type cooldownStore interface {
	SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error
}

// PreClaimHook matches the work pre-claim hook signature.
type PreClaimHook func(ctx context.Context) error

// PreClaimGuard implements the two-strikes pre-claim policy. The first hook
// failure skips the candidate and retries it on the next presentation; the
// second failure parks the bead on execution cooldown.
type PreClaimGuard struct {
	hook     PreClaimHook
	store    cooldownStore
	log      io.Writer
	now      func() time.Time
	cooldown time.Duration
	timeout  time.Duration

	mu             sync.Mutex
	failCounts     map[string]int
	loggedSystemic map[string]bool
}

// NewPreClaimGuard constructs a Guard that owns the pre-claim hook retry
// state for one worker run.
func NewPreClaimGuard(hook PreClaimHook, store cooldownStore, log io.Writer, now func() time.Time, cooldown, timeout time.Duration) *PreClaimGuard {
	if now == nil {
		now = time.Now
	}
	if cooldown <= 0 {
		cooldown = 30 * time.Second
	}
	if timeout <= 0 {
		timeout = DefaultPreClaimTimeout
	}
	return &PreClaimGuard{
		hook:           hook,
		store:          store,
		log:            log,
		now:            now,
		cooldown:       cooldown,
		timeout:        timeout,
		failCounts:     make(map[string]int),
		loggedSystemic: make(map[string]bool),
	}
}

// Allow runs the pre-claim hook and applies the two-strikes retry policy.
func (g *PreClaimGuard) Allow(ctx context.Context, beadID string) (bool, string) {
	if g == nil || g.hook == nil {
		return true, ""
	}
	err, timedOut := callPreClaimHookWithTimeout(ctx, g.hook, g.timeout)
	if err != nil || timedOut {
		switch classifyPreClaimError(err) {
		case preClaimClassTrackerContention:
			reason := err.Error()
			g.mu.Lock()
			shouldLog := !g.loggedSystemic[reason]
			g.loggedSystemic[reason] = true
			g.mu.Unlock()
			if shouldLog && g.log != nil {
				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (transient tracker-file contention; leaving beads untouched)\n", err)
			}
			return false, TrackerContentionPreClaimReasonPrefix + reason
		case preClaimClassSystemic:
			reason := err.Error()
			g.mu.Lock()
			shouldLog := !g.loggedSystemic[reason]
			g.loggedSystemic[reason] = true
			g.mu.Unlock()
			if shouldLog && g.log != nil {
				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (systemic; leaving beads untouched)\n", err)
			}
			return false, SystemicPreClaimReasonPrefix + reason
		}

		g.mu.Lock()
		defer g.mu.Unlock()

		g.failCounts[beadID]++
		if g.failCounts[beadID] >= 2 {
			if g.store != nil {
				until := g.now().UTC().Add(g.cooldown)
				detail := "pre-claim hook failed"
				if err != nil {
					detail = err.Error()
				} else if timedOut {
					detail = fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
				}
				_ = g.store.SetExecutionCooldown(beadID, until, "preclaim-hook-failed", detail, "")
			}
		}
		if g.log != nil {
			switch {
			case timedOut:
				_, _ = fmt.Fprintf(g.log, "pre-claim hook timed out after %s (skipping %s)\n", g.timeout, beadID)
			case err != nil:
				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (skipping %s)\n", err, beadID)
			}
		}
		if timedOut {
			return false, fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
		}
		return false, err.Error()
	}

	g.mu.Lock()
	delete(g.failCounts, beadID)
	g.mu.Unlock()
	return true, ""
}

func IsSystemicPreClaimSkipReason(reason string) bool {
	return strings.HasPrefix(reason, SystemicPreClaimReasonPrefix)
}

func SystemicPreClaimDetail(reason string) string {
	return strings.TrimPrefix(reason, SystemicPreClaimReasonPrefix)
}

func IsTrackerContentionPreClaimSkipReason(reason string) bool {
	return strings.HasPrefix(reason, TrackerContentionPreClaimReasonPrefix)
}

// IsManagedTrackerPath reports whether path is one of the DDx-managed tracker
// or durable-audit files that workers rewrite continuously.
func IsManagedTrackerPath(path string) bool {
	return trackerpaths.IsManagedTrackerPath(path)
}

func TrackerContentionPreClaimDetail(reason string) string {
	return strings.TrimPrefix(reason, TrackerContentionPreClaimReasonPrefix)
}

// classifyPreClaimError categorizes a pre-claim hook error. Systemic and
// tracker-contention classes both idle the worker without cooldowning the bead
// (no bead is at fault); they differ only in the reason code surfaced to
// operators. Anything else is treated as bead-specific and runs through the
// two-strikes cooldown policy.
func classifyPreClaimError(err error) preClaimClass {
	if err == nil {
		return preClaimClassBeadSpecific
	}
	msg := err.Error()
	// Staged tracker-file contention: a landing-worktree "staged changes" error
	// whose staged paths are exclusively DDx-managed tracker/metadata files.
	// Another worker's tracker commit is partially staged; the index settles
	// within milliseconds. Treating this as bead-specific would wrongly cooldown
	// beads during a transient multi-worker commit race (ddx-df77e668).
	if isStagedTrackerContentionError(msg) {
		return preClaimClassTrackerContention
	}
	// Branch divergence: local tracker has diverged from origin.
	if strings.Contains(msg, "local branch ") && strings.Contains(msg, " has diverged from origin ") {
		return preClaimClassSystemic
	}
	// Staged changes that include code/doc/test files: real work was never
	// committed. This is a systemic repo state, not a transient contention.
	if strings.Contains(msg, "staged changes") {
		return preClaimClassSystemic
	}
	// Git index.lock: an external git process holds the index lock. This is
	// transient (sub-second for normal operations); no bead is at fault.
	if strings.Contains(msg, "index.lock") {
		return preClaimClassSystemic
	}
	// Corrupt landing indexes are repo-health failures, not bead-specific
	// failures. Surface once as systemic so the worker can auto-repair or ask
	// for operator intervention without cooldowning beads.
	if strings.Contains(msg, "index file smaller than expected") ||
		strings.Contains(msg, "repairing landing worktree index") {
		return preClaimClassSystemic
	}
	return preClaimClassBeadSpecific
}

// isStagedTrackerContentionError reports whether a "landing worktree has staged
// changes" error lists only DDx-managed tracker/metadata files. A mixed or
// code-only staged set is NOT tracker contention (it is systemic).
func isStagedTrackerContentionError(msg string) bool {
	if !strings.Contains(msg, "staged changes after waiting") {
		return false
	}
	paths := stagedPathsFromError(msg)
	if len(paths) == 0 {
		return false
	}
	for _, p := range paths {
		if !isTrackerMetadataPath(p) {
			return false
		}
	}
	return true

