	runtime := AgentRunRuntime{
		Prompt:      "do stuff",
		WorkDir:     "/tmp/wd-arrt",
		Correlation: map[string]string{"trace_id": "abc"},
	}

	result, err := runnerRunWithConfig(r, context.Background(), rcfg, runtime)
	require.NoError(t, err)
	require.NotNil(t, result)
