entity {\\n793\\t    pub provider: String,\\n794\\t    pub external_id: String,\\n795\\t    pub user_id: UserId,\\n796\\t}\\n797\\t\\n798\\t/// A user's membership in a tenant.\\n799\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n800\\tpub struct TenantMember {\\n801\\t    pub tenant_id: TenantId,\\n802\\t    pub user_id: UserId,\\n803\\t    pub role: TenantRole,\\n804\\t}\\n805\\t\\n806\\t/// Role a user has within a tenant.\\n807\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash, Serialize, Deserialize)]\\n808\\tpub enum TenantRole {\\n809\\t    Admin,\\n810\\t    Write,\\n811\\t    Read,\\n812\\t}\\n813\\t\\n814\\timpl TenantRole {\\n815\\t    /// Returns the operations this role can delegate (ceiling).\\n816\\t    ///\\n817\\t    /// - `Admin` → `{Read, Write, Admin}`\\n818\\t    /// - `Write` → `{Read, Write}`\\n819\\t    /// - `Read` → `{Read}`\\n820\\t    pub fn delegation_ops(\u0026self) -\u003e Vec\u003cOp\u003e {\\n821\\t        match self {\\n822\\t            TenantRole::Admin =\u003e vec![Op::Read, Op::Write, Op::Admin],\\n823\\t            TenantRole::Write =\u003e vec![Op::Read, Op::Write],\\n824\\t            TenantRole::Read =\u003e vec![Op::Read],\\n825\\t        }\\n826\\t    }\\n827\\t}\\n828\\t\\n829\\t/// An operation that can be granted.\\n830\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n831\\tpub enum Op {\\n832\\t    Read,\\n833\\t    Write,\\n834\\t    Admin,\\n835\\t}\\n836\\t\\n837\\t/// A database with a set of granted operations.\\n838\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n839\\tpub struct GrantedDatabase {\\n840\\t    pub name: String,\\n841\\t    pub ops: Vec\u003cOp\u003e,\\n842\\t}\\n843\\t\\n844\\t/// A collection of database grants.\\n845\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n846\\tpub struct Grants {\\n847\\t    pub databases: Vec\u003cGrantedDatabase\u003e,\\n848\\t}\\n849\\t\\n850\\timpl Grants {\\n851\\t    /// Validate the grants structure according to the v5 schema.\\n852\\t    ///\\n853\\t    /// - At most 1024 databases\\n854\\t    /// - Each database must have at least one op\\n855\\t    /// - Each op must be unique (no duplicates)\\n856\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n857\\t        if self.databases.len() \u003e 1024 {\\n858\\t            return Err(AuthError::GrantsMalformed);\\n859\\t        }\\n860\\t        for db in \u0026self.databases {\\n861\\t            db.validate()?;\\n862\\t        }\\n863\\t        Ok(())\\n864\\t    }\\n865\\t}\\n866\\t\\n867\\timpl GrantedDatabase {\\n868\\t    /// Validate a single granted database.\\n869\\t    ///\\n870\\t    /// - name must be non-empty\\n871\\t    /// - ops must not be empty\\n872\\t    /// - ops must be unique\\n873\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n874\\t        if self.name.is_empty() {\\n875\\t            return Err(AuthError::GrantsMalformed);\\n876\\t        }\\n877\\t        if self.ops.is_empty() {\\n878\\t            return Err(AuthError::GrantsMalformed);\\n879\\t        }\\n880\\t        // Check for duplicate ops\\n881\\t        let unique_ops: std::collections::HashSet\u003c_\u003e = self.ops.iter().collect();\\n882\\t        if unique_ops.len() != self.ops.len() {\\n883\\t            return Err(AuthError::GrantsMalformed);\\n884\\t        }\\n885\\t        Ok(())\\n886\\t    }\\n887\\t}\\n888\\t\\n889\\t/// JWT claims for tenant-scoped credentials (ADR-018 §4).\\n890\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n891\\tpub struct JwtClaims {\\n892\\t    pub iss: String,\\n893\\t    pub sub: String,\\n894\\t    pub aud: String,\\n895\\t    pub jti: String,\\n896\\t    pub iat: u64,\\n897\\t    pub nbf: u64,\\n898\\t    pub exp: u64,\\n899\\t    pub grants: Grants,\"}]},\"parent_tool_use_id\":null,\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"d1d46767-b416-4b0c-b7ae-bfff2fc54fb3\",\"timestamp\":\"2026-04-15T01:32:06.212Z\",\"tool_use_result\":{\"type\":\"text\",\"file\":{\"filePath\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-core/src/auth.rs\",\"content\":\"        writer.apply_masks(\u0026mut data, \u0026policies);\\n        assert!(\\n            data.get(\\\"internal_notes\\\").is_some(),\\n            \\\"writer should see write-level fields\\\"\\n        );\\n    }\\n\\n    #[test]\\n    fn reader_cannot_see_write_level_fields() {\\n        let reader = CallerIdentity::new(\\\"dave\\\", Role::Read);\\n        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"internal_notes\\\": \\\"sensitive\\\"});\\n        let policies = vec![MaskPolicy {\\n            field: \\\"internal_notes\\\".into(),\\n            min_role: Role::Write,\\n        }];\\n        reader.apply_masks(\u0026mut data, \u0026policies);\\n        assert!(\\n            data.get(\\\"internal_notes\\\").is_none(),\\n            \\\"reader should not see write-level fields\\\"\\n        );\\n    }\\n\\n    #[test]\\n    fn multiple_mask_policies() {\\n        let reader = CallerIdentity::new(\\\"eve\\\", Role::Read);\\n        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000, \\\"ssn\\\": \\\"123-45-6789\\\"});\\n        let policies = vec![\\n            MaskPolicy {\\n                field: \\\"salary\\\".into(),\\n                min_role: Role::Admin,\\n            },\\n            MaskPolicy {\\n                field: \\\"ssn\\\".into(),\\n                min_role: Role::Write,\\n            },\\n        ];\\n        reader.apply_masks(\u0026mut data, \u0026policies);\\n        assert!(data.get(\\\"salary\\\").is_none());\\n        assert!(data.get(\\\"ssn\\\").is_none());\\n        assert!(data.get(\\\"name\\\").is_some());\\n    }\\n\\n    #[test]\\n    fn mask_on_non_object_is_noop() {\\n        let reader = CallerIdentity::new(\\\"f\\\", Role::Read);\\n        let mut data = serde_json::json!(\\\"just a string\\\");\\n        let policies = vec![MaskPolicy {\\n            field: \\\"anything\\\".into(),\\n            min_role: Role::Admin,\\n        }];\\n        reader.apply_masks(\u0026mut data, \u0026policies);\\n        assert_eq!(data, serde_json::json!(\\\"just a string\\\"));\\n    }\\n\\n    // ── ABAC write policy tests (US-047) ───────────────────────────────\\n\\n    #[test]\\n    fn write_policy_allows_matching_role() {\\n        let policy = WritePolicy {\\n            collection: \\\"tasks\\\".into(),\\n            min_write_role: Role::Write,\\n            immutable_fields: vec![],\\n        };\\n        let caller = CallerIdentity::new(\\\"alice\\\", Role::Write);\\n        assert!(policy.check_write(\u0026caller).is_ok());\\n    }\\n\\n    #[test]\\n    fn write_policy_denies_insufficient_role() {\\n        let policy = WritePolicy {\\n            collection: \\\"tasks\\\".into(),\\n            min_write_role: Role::Admin,\\n            immutable_fields: vec![],\\n        };\\n        let caller = CallerIdentity::new(\\\"bob\\\", Role::Write);\\n        assert!(policy.check_write(\u0026caller).is_err());\\n    }\\n\\n    #[test]\\n    fn immutable_fields_detected() {\\n        let policy = WritePolicy {\\n            collection: \\\"tasks\\\".into(),\\n            min_write_role: Role::Write,\\n            immutable_fields: vec![\\\"created_by\\\".into(), \\\"source\\\".into()],\\n        };\\n\\n        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"created_by\\\": \\\"alice\\\", \\\"source\\\": \\\"api\\\"});\\n        let new_data = serde_json::json!({\\\"title\\\": \\\"T2\\\", \\\"created_by\\\": \\\"alice\\\", \\\"source\\\": \\\"api\\\"});\\n        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n        assert!(violations.is_empty());\\n\\n        let changed = serde_json::json!({\\\"title\\\": \\\"T2\\\", \\\"created_by\\\": \\\"bob\\\", \\\"source\\\": \\\"api\\\"});\\n        let violations = policy.check_immutable_fields(\u0026old_data, \u0026changed);\\n        assert_eq!(violations, vec![\\\"created_by\\\"]);\\n    }\\n\\n    #[test]\\n    fn immutable_field_added_is_ok() {\\n        // Adding an immutable field to an entity that didn't have it is OK.\\n        let policy = WritePolicy {\\n            collection: \\\"tasks\\\".into(),\\n            min_write_role: Role::Write,\\n            immutable_fields: vec![\\\"locked\\\".into()],\\n        };\\n        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\"});\\n        let new_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"locked\\\": true});\\n        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n        assert!(violations.is_empty());\\n    }\\n\\n    #[test]\\n    fn immutable_field_removed_is_violation() {\\n        let policy = WritePolicy {\\n            collection: \\\"tasks\\\".into(),\\n            min_write_role: Role::Write,\\n            immutable_fields: vec![\\\"source\\\".into()],\\n        };\\n        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"source\\\": \\\"api\\\"});\\n        let new_data = serde_json::json!({\\\"title\\\": \\\"T2\\\"});\\n        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n        assert_eq!(violations, vec![\\\"source\\\"]);\\n    }\\n\\n    // ── Database grant tests (US-038) ──────────────────────────────────\\n\\n    #[test]\\n    fn grant_registry_empty_denies_all() {\\n        let registry = GrantRegistry::new();\\n        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Read).is_err());\\n    }\\n\\n    #[test]\\n    fn exact_grant_allows_access() {\\n        let mut registry = GrantRegistry::new();\\n        registry.add(DatabaseGrant {\\n            actor: \\\"alice\\\".into(),\\n            database: \\\"prod\\\".into(),\\n            role: Role::Write,\\n        });\\n        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::Write);\\n        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Write).is_ok());\\n        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Admin).is_err());\\n    }\\n\\n    #[test]\\n    fn wildcard_actor_grant() {\\n        let mut registry = GrantRegistry::new();\\n        registry.add(DatabaseGrant {\\n            actor: \\\"*\\\".into(),\\n            database: \\\"public\\\".into(),\\n            role: Role::Read,\\n        });\\n        assert_eq!(registry.effective_role(\\\"anyone\\\", \\\"public\\\"), Role::Read);\\n        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"public\\\"), Role::Read);\\n    }\\n\\n    #[test]\\n    fn wildcard_database_grant() {\\n        let mut registry = GrantRegistry::new();\\n        registry.add(DatabaseGrant {\\n            actor: \\\"admin-bot\\\".into(),\\n            database: \\\"*\\\".into(),\\n            role: Role::Admin,\\n        });\\n        assert_eq!(\\n            registry.effective_role(\\\"admin-bot\\\", \\\"any-database\\\"),\\n            Role::Admin\\n        );\\n    }\\n\\n    #[test]\\n    fn highest_privilege_wins() {\\n        let mut registry = GrantRegistry::new();\\n        registry.add(DatabaseGrant {\\n            actor: \\\"alice\\\".into(),\\n            database: \\\"prod\\\".into(),\\n            role: Role::Read,\\n        });\\n        registry.add(DatabaseGrant {\\n            actor: \\\"alice\\\".into(),\\n            database: \\\"prod\\\".into(),\\n            role: Role::Admin,\\n        });\\n        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::Admin);\\n    }\\n\\n    #[test]\\n    fn no_cross_database_access_without_grant() {\\n        let mut registry = GrantRegistry::new();\\n        registry.add(DatabaseGrant {\\n            actor: \\\"alice\\\".into(),\\n            database: \\\"dev\\\".into(),\\n            role: Role::Admin,\\n        });\\n        // alice has no grant on prod\\n        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n    }\\n\\n    #[test]\\n    fn revoke_removes_grants() {\\n        let mut registry = GrantRegistry::new();\\n        registry.add(DatabaseGrant {\\n            actor: \\\"alice\\\".into(),\\n            database: \\\"prod\\\".into(),\\n            role: Role::Write,\\n        });\\n        registry.revoke(\\\"alice\\\", \\\"prod\\\");\\n        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n    }\\n}\\n\\n// ── ADR-018: Tenant/User/Credential types ───────────────────────────────────\\n\\nuse uuid::Uuid;\\n\\n/// Stable identifier for a tenant.\\n#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n#[serde(transparent)]\\npub struct TenantId(pub String);\\n\\nimpl TenantId {\\n    /// Generate a fresh tenant id (UUIDv7 string).\\n    pub fn generate() -\u003e Self {\\n        Self(Uuid::now_v7().to_string())\\n    }\\n\\n    /// Wrap an existing id string.\\n    pub fn new(id: impl Into\u003cString\u003e) -\u003e Self {\\n        Self(id.into())\\n    }\\n\\n    pub fn as_str(\u0026self) -\u003e \u0026str {\\n        \u0026self.0\\n    }\\n}\\n\\nimpl std::fmt::Display for TenantId {\\n    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n        write!(f, \\\"{}\\\", self.0)\\n    }\\n}\\n\\n/// Stable identifier for a user.\\n#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n#[serde(transparent)]\\npub struct UserId(pub String);\\n\\nimpl UserId {\\n    /// Generate a fresh user id (UUIDv7 string).\\n    pub fn generate() -\u003e Self {\\n        Self(Uuid::now_v7().to_string())\\n    }\\n\\n    /// Wrap an existing id string.\\n    pub fn new(id: impl Into\u003cString\u003e) -\u003e Self {\\n        Self(id.into())\\n    }\\n\\n    pub fn as_str(\