type cancelOnMatchWriter struct {
	bytes.Buffer
	match  string
	cancel context.CancelFunc
	once   sync.Once
}

func (w *cancelOnMatchWriter) Write(p []byte) (int, error) {
	n, err := w.Buffer.Write(p)
	if w.cancel != nil && strings.Contains(string(p), w.match) {
		w.once.Do(w.cancel)
	}
	return n, err
}

type loopEvent struct {
	Type string
	Data map[string]any
}

func parseLoopEvents(t *testing.T, raw string) []loopEvent {
	t.Helper()

	var events []loopEvent
	for _, line := range strings.Split(strings.TrimSpace(raw), "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		typ, _ := entry["type"].(string)
		if typ == "" {
			continue
		}
		data, _ := entry["data"].(map[string]any)
		events = append(events, loopEvent{Type: typ, Data: data})
	}
	return events
}

func loopEventDataByType(events []loopEvent, typ string) []map[string]any {
	var out []map[string]any
	for _, event := range events {
		if event.Type == typ {
			out = append(out, event.Data)
		}
	}
	return out
}

	// Use a tiny poll interval so the test runs quickly; cancel after enough
	// wall-clock for several empty-poll cycles to confirm the loop is still
	// running and not bailing out after the first empty poll.
	ctx, cancel := context.WithCancel(context.Background())
	pollInterval := 5 * time.Millisecond
	cancelAfter := 50 * time.Millisecond
	go func() {
		time.Sleep(cancelAfter)
		cancel()
	}()

	start := time.Now()
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:         executeloop.ModeWatch,
		IdleInterval: pollInterval,
	})
	elapsed := time.Since(start)

	// Context cancellation surfaces as the returned error. The key
	// invariant: the loop survived past the first empty poll.
	require.ErrorIs(t, err, context.Canceled)
	require.NotNil(t, result)
	assert.Equal(t, 0, result.Attempts)
	assert.True(t, elapsed >= cancelAfter,
		"loop must run until ctx cancellation; ran for %s, expected >= %s", elapsed, cancelAfter)
}

