func defaultWorkBinaryReexec(exe string, argv []string, dir string) error {
	replacement := exec.Command(exe, argv[1:]...)
	replacement.Dir = dir
	replacement.Env = os.Environ()
	replacement.Stdin = os.Stdin
	replacement.Stdout = os.Stdout
