func TestWorkWatch_DoesNotReexecMidBead(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	require.NoError(t, store.Create(context.Background(), &bead.Bead{
		ID:       "ddx-mid-bead-refresh",
		Title:    "refresh boundary bead",
		Priority: 0,
	}))

	worker := &ExecuteBeadWorker{
		Store: store,
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	release := make(chan struct{})
	started := make(chan struct{})
	worker.Executor = ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		close(started)
		select {
		case <-release:
		case <-ctx.Done():
			return ExecuteBeadReport{}, ctx.Err()
		}
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			ResultRev: "rev-" + beadID,
		}, nil
	})

	var checks atomic.Int32
	done := make(chan struct{})
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	go func() {
		defer close(done)
		_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
			Mode:         executeloop.ModeWatch,
			IdleInterval: time.Hour,
			BinaryRefreshCheck: func(ctx context.Context) (bool, error) {
				checks.Add(1)
				return false, nil
			},
			Log: io.Discard,
		})
	}()

	// Use the executor itself as the "bead is running" signal: once it starts
	// we know the worker has already passed the binary-refresh boundary for this
	// bead and must not re-check until the attempt completes.
	select {
	case <-started:
	case <-time.After(2 * time.Second):
		t.Fatal("executor did not start")
	}

	initialChecks := checks.Load()
	time.Sleep(50 * time.Millisecond)
	assert.Equal(t, initialChecks, checks.Load(), "binary refresh must not fire while the bead is executing")
	close(release)
	require.Eventually(t, func() bool {
		return checks.Load() > initialChecks
	}, 2*time.Second, 10*time.Millisecond)
	cancel()
	<-done
}

